#!/usr/bin/env node
// Harness for the scheduler backtest (js/backtest.js, Phase S20): the
// prediction scoring, the grade→quality inverse, and the dual-engine replay
// over a review log — including a synthetic log generated by the FSRS model,
// on which FSRS should score no worse than the SM-2 proxy (the backtest
// analogue of the optimiser's "recovers lower loss from synthetic data").
//
// Usage:  node scripts/verify-backtest.mjs [--quiet]
// Exit code: 0 = all pass, 1 = any fail.

import { pathToFileURL, fileURLToPath } from 'node:url';
import path from 'node:path';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT = path.resolve(__dirname, '..');
const QUIET = process.argv.includes('--quiet');

const bt = await import(pathToFileURL(path.join(ROOT, 'js/backtest.js')).href);
const { backtestEngines, scorePredictions, gradeToQuality } = bt;
const { FSRS_DEFAULT_W, initStability, initDifficulty, nextDifficulty, stabilityOnSuccess, stabilityOnLapse, retrievability } =
  await import(pathToFileURL(path.join(ROOT, 'js/fsrs.js')).href);
const { addDays } = await import(pathToFileURL(path.join(ROOT, 'js/util.js')).href);

const results = [];
function check(section, label, cond, detail = '') {
  results.push({ section, ok: !!cond });
  if (!QUIET && !cond) console.log(`  [${section}] ✗ ${label}${detail ? ': ' + detail : ''}`);
}

// Deterministic PRNG (mulberry32) so the synthetic log is reproducible.
function mulberry32(seed) {
  let s = seed >>> 0;
  return function () {
    s = (s + 0x6D2B79F5) >>> 0;
    let t = s;
    t = Math.imul(t ^ (t >>> 15), t | 1);
    t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

// ─── BT1: gradeToQuality inverse preserves the lapse boundary ──────────
check('BT1', 'grade 1 → quality 2 (<3, lapse)', gradeToQuality(1) === 2);
check('BT1', 'grade 2 → quality 3 (≥3, pass)', gradeToQuality(2) === 3);
check('BT1', 'grade 3 → quality 4', gradeToQuality(3) === 4);
check('BT1', 'grade 4 → quality 5', gradeToQuality(4) === 5);

// ─── BT2: scorePredictions ─────────────────────────────────────────────
{
  check('BT2', 'empty ⇒ zeroed', scorePredictions([]).n === 0);
  const perfect = [{ R: 1 - 1e-6, recalled: 1 }, { R: 1e-6, recalled: 0 }];
  const sp = scorePredictions(perfect);
  check('BT2', 'confident-correct ⇒ ~0 log-loss', sp.logLoss < 1e-4);
  check('BT2', 'confident-correct ⇒ accuracy 1', sp.accuracy === 1);
  check('BT2', 'confident-correct ⇒ ~0 brier', sp.brier < 1e-6);
  const wrong = [{ R: 1e-6, recalled: 1 }, { R: 1 - 1e-6, recalled: 0 }];
  const sw = scorePredictions(wrong);
  check('BT2', 'confident-wrong ⇒ large log-loss', sw.logLoss > 5);
  check('BT2', 'confident-wrong ⇒ accuracy 0', sw.accuracy === 0);
  const half = scorePredictions([{ R: 0.5, recalled: 1 }, { R: 0.5, recalled: 0 }]);
  check('BT2', 'R=0.5 ⇒ log-loss ≈ ln2', Math.abs(half.logLoss - Math.log(2)) < 1e-9);
  check('BT2', 'R=0.5 ⇒ brier = 0.25', Math.abs(half.brier - 0.25) < 1e-9);
}

// ─── BT3: insufficient data ────────────────────────────────────────────
{
  check('BT3', 'empty log ⇒ not enough, n=0', backtestEngines([]).enough === false && backtestEngines([]).n === 0);
  const tiny = [
    { cardId: 'x', ts: '2026-01-01', grade: 3, elapsed: 0 },
    { cardId: 'x', ts: '2026-01-05', grade: 3, elapsed: 4 },
  ];
  const r = backtestEngines(tiny, { minPredictions: 20 });
  check('BT3', '1 prediction < min ⇒ enough=false', r.enough === false && r.n === 1 && r.winner === null);
}

// ─── BT4: structure + equal prediction counts ──────────────────────────
{
  // a few cards, several reviews each, mixed grades
  const log = [];
  for (let c = 0; c < 6; c++) {
    let ts = '2026-01-01';
    for (let i = 0; i < 6; i++) {
      const grade = (c + i) % 5 === 0 ? 1 : (i % 3 === 0 ? 2 : (i % 2 === 0 ? 4 : 3));
      log.push({ cardId: `c${c}`, ts, grade, elapsed: i === 0 ? 0 : (i * 2 + c) });
      ts = addDays(ts, i * 2 + c + 1);
    }
  }
  const r = backtestEngines(log, { minPredictions: 10 });
  check('BT4', 'enough data', r.enough === true);
  check('BT4', 'FSRS and SM-2 share the same prediction count', r.fsrs.n === r.sm2.n && r.fsrs.n === r.n);
  check('BT4', 'n = total reviews − cards (first review per card initialises)', r.n === log.length - r.cards);
  check('BT4', 'log-loss positive for both', r.fsrs.logLoss > 0 && r.sm2.logLoss > 0);
  check('BT4', 'accuracy in [0,1] for both', r.fsrs.accuracy >= 0 && r.fsrs.accuracy <= 1 && r.sm2.accuracy >= 0 && r.sm2.accuracy <= 1);
  check('BT4', 'brier in [0,1] for both', r.fsrs.brier >= 0 && r.fsrs.brier <= 1 && r.sm2.brier >= 0 && r.sm2.brier <= 1);
  check('BT4', 'winner consistent with log-loss', r.winner === (r.fsrs.logLoss < r.sm2.logLoss ? 'fsrs' : 'sm2'));
  check('BT4', 'margin = |Δ log-loss|', Math.abs(r.margin - Math.abs(r.fsrs.logLoss - r.sm2.logLoss)) < 1e-12);
}

// ─── BT5: determinism ──────────────────────────────────────────────────
{
  const log = [
    { cardId: 'a', ts: '2026-02-01', grade: 3, elapsed: 0 },
    { cardId: 'a', ts: '2026-02-04', grade: 4, elapsed: 3 },
    { cardId: 'a', ts: '2026-02-20', grade: 2, elapsed: 16 },
  ];
  const r1 = backtestEngines(log, { minPredictions: 1 });
  const r2 = backtestEngines(log, { minPredictions: 1 });
  check('BT5', 'identical inputs ⇒ identical scores', r1.fsrs.logLoss === r2.fsrs.logLoss && r1.sm2.logLoss === r2.sm2.logLoss);
}

// ─── BT6: trained-weights flag ─────────────────────────────────────────
{
  const log = [
    { cardId: 'a', ts: '2026-03-01', grade: 3, elapsed: 0 },
    { cardId: 'a', ts: '2026-03-05', grade: 3, elapsed: 4 },
  ];
  check('BT6', 'default weights ⇒ usedTrainedWeights false', backtestEngines(log, { minPredictions: 1 }).usedTrainedWeights === false);
  const trained = FSRS_DEFAULT_W.map((x, i) => (i === 8 ? x * 1.1 : x));
  check('BT6', 'custom 17-vector ⇒ usedTrainedWeights true', backtestEngines(log, { weights: trained, minPredictions: 1 }).usedTrainedWeights === true);
  check('BT6', 'bad weights length ⇒ falls back, flag false', backtestEngines(log, { weights: [1, 2, 3], minPredictions: 1 }).usedTrainedWeights === false);
}

// ─── BT7: FSRS fits its own generative process ≥ as well as the proxy ──
{
  // Generate reviews where recall ~ Bernoulli(R_fsrs) under default weights.
  const rnd = mulberry32(424242);
  const w = FSRS_DEFAULT_W;
  const log = [];
  const NCARDS = 60, NREV = 8;
  for (let c = 0; c < NCARDS; c++) {
    let ts = '2026-01-01';
    let grade0 = rnd() < 0.8 ? 3 : 2;
    let S = initStability(grade0, w);
    let D = initDifficulty(grade0, w);
    log.push({ cardId: `g${c}`, ts, grade: grade0, elapsed: 0 });
    for (let i = 1; i < NREV; i++) {
      const elapsed = 1 + Math.floor(rnd() * Math.max(1, S));        // review near/after the stability horizon
      const R = retrievability(elapsed, S);
      const recalled = rnd() < R;
      const grade = recalled ? (rnd() < 0.3 ? 4 : 3) : 1;
      ts = addDays(ts, elapsed);
      log.push({ cardId: `g${c}`, ts, grade, elapsed });
      D = nextDifficulty(D, grade, w);
      S = Math.max(0.1, grade === 1 ? stabilityOnLapse(D, S, R, w) : stabilityOnSuccess(D, S, R, grade, w));
    }
  }
  const r = backtestEngines(log, { minPredictions: 20 });
  check('BT7', 'plenty of predictions', r.enough && r.n >= NCARDS * (NREV - 1) - 5);
  check('BT7', 'FSRS log-loss ≤ SM-2 proxy log-loss on FSRS-generated data', r.fsrs.logLoss <= r.sm2.logLoss + 1e-6, `fsrs=${r.fsrs.logLoss.toFixed(4)} sm2=${r.sm2.logLoss.toFixed(4)}`);
  check('BT7', 'winner is fsrs on its own generative process', r.winner === 'fsrs');
}

const passed = results.filter((r) => r.ok).length;
console.log(`\nTotal: ${passed}/${results.length}`);
if (passed === results.length) console.log('All checks pass. Scheduler backtest (scoring + dual-engine replay) verified.');
process.exit(passed === results.length ? 0 : 1);
